package org.example;

import org.example.bai1.Bai1;
import org.example.bai2.Bai2;
import org.example.bai3.Bai3;
import org.example.bai4.Bai4;
import org.example.bai5.Bai5App;

//TIP To <b>Run</b> code, press <shortcut actionId="Run"/> or
// click the <icon src="AllIcons.Actions.Execute"/> icon in the gutter.
public class Main {
    public static void main(String[] args) {
        // Chạy theo tham số: bai1 | bai2
        if (args != null && args.length > 0) {
            if ("bai1".equalsIgnoreCase(args[0])) {
                Bai1.main(args);
                return;
            }
            if ("bai2".equalsIgnoreCase(args[0])) {
                Bai2.main(args);
                return;
            }
            if ("bai3".equalsIgnoreCase(args[0])) {
                // args[1] (nếu có) sẽ là bedId
                String[] forwarded = new String[Math.max(args.length - 1, 0)];
                if (args.length > 1) {
                    System.arraycopy(args, 1, forwarded, 0, args.length - 1);
                }
                Bai3.main(forwarded);
                return;
            }
            if ("bai4".equalsIgnoreCase(args[0])) {
                // args[1] (nếu có) sẽ là patient name input
                String[] forwarded = new String[Math.max(args.length - 1, 0)];
                if (args.length > 1) {
                    System.arraycopy(args, 1, forwarded, 0, args.length - 1);
                }
                Bai4.main(forwarded);
                return;
            }
            if ("bai5".equalsIgnoreCase(args[0])) {
                Bai5App.main(new String[0]);
                return;
            }
        }

        // Mặc định chạy bài 2
        Bai2.main(args);
    }
}

package org.example.bai1;

import java.sql.Connection;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;

/**
 * Bài 1 - Module Kết nối hệ thống lưu trữ bệnh án.
 */
public class Bai1 {

    /**
     * PHẦN 1 - PHÂN TÍCH (tóm tắt ngay trong code để nộp bài):
     *
     * - Nếu mỗi lần truy vấn đều mở Connection mới nhưng không close():
     *   1) RÒ RỈ TÀI NGUYÊN (resource leak): Connection/Socket/TCP, thread, buffer phía client & server.
     *      Sau vài giờ hệ thống sẽ đạt giới hạn (max connections / file descriptors), gây treo hoặc chậm dần.
     *   2) TĂNG TẢI DB & NETWORK: DB phải giữ session/transaction context; network giữ socket half-open.
     *      Dẫn đến lỗi "Communications link failure" (đứt kết nối/keepalive timeout/DB reset).
     *   3) ẢNH HƯỞNG HỆ THỐNG 24/7: bệnh viện cần realtime (cấp cứu, kê đơn, xét nghiệm).
     *      Treo phần mềm có thể làm gián đoạn quy trình, chậm xử lý, sai lệch dữ liệu.
     *   4) KHÓ TRIỆU CHỨNG: lỗi thường xuất hiện muộn (sau vài tiếng), khó debug, ảnh hưởng diện rộng.
     *
     * - Giải pháp: quản lý tập trung cấu hình, đảm bảo đóng tài nguyên ở finally (hoặc try-with-resources),
     *   ưu tiên dùng connection pool (HikariCP) trong dự án thực tế.
     */

    /**
     * PHẦN 2 - THỰC THI:
     * Demo 1 truy vấn đơn giản, bảo đảm mọi tài nguyên được đóng tại finally.
     */
    public static void demoQuery() {
        Connection conn = null;
        Statement st = null;
        ResultSet rs = null;

        try {
            conn = DBContext.getConnection();
            st = conn.createStatement();

            // Query mẫu để test kết nối. Có thể thay bằng bảng thật.
            rs = st.executeQuery("SELECT 1 AS ok");

            while (rs.next()) {
                System.out.println("DB ok = " + rs.getInt("ok"));
            }

        } catch (SQLException e) {
            System.err.println("DB error: " + e.getMessage());
        } finally {
            // Đóng theo thứ tự ngược lại lúc mở
            DBContext.closeQuietly(rs);
            DBContext.closeQuietly(st);
            DBContext.closeQuietly(conn);
        }
    }

    public static void main(String[] args) {
        demoQuery();
    }
}

package org.example.bai1;

import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;

/**
 * DBContext: quản lý kết nối DB theo cấu hình tập trung.
 *
 * Yêu cầu bài: dùng hằng số cấu hình và đảm bảo mọi phương thức truy vấn
 * đều phải đóng kết nối trong khối finally.
 */
public final class DBContext {

    // ====== Cấu hình tập trung (theo đề bài) ======
    public static final String DB_URL = "jdbc:mysql://192.168.1.10:3306/Hospital_DB";
    public static final String DB_USER = "admin";
    public static final String DB_PASSWORD = "med123";

    /**
     * Với MySQL Connector/J 8+ driver tự đăng ký, nhưng khai báo hằng số để rõ ràng.
     */
    public static final String JDBC_DRIVER = "com.mysql.cj.jdbc.Driver";

    private DBContext() {
        // utility class
    }

    public static Connection getConnection() throws SQLException {
        try {
            Class.forName(JDBC_DRIVER);
        } catch (ClassNotFoundException e) {
            // chuyển sang unchecked exception để báo lỗi cấu hình sớm
            throw new IllegalStateException("Missing JDBC driver: " + JDBC_DRIVER, e);
        }
        return DriverManager.getConnection(DB_URL, DB_USER, DB_PASSWORD);
    }

    // ====== Helpers đóng tài nguyên an toàn (phục vụ finally) ======
    public static void closeQuietly(AutoCloseable c) {
        if (c == null) return;
        try {
            c.close();
        } catch (Exception ignored) {
            // không ném tiếp để tránh che lỗi chính
        }
    }
}

package org.example.bai2;

import org.example.bai1.DBContext;

import java.sql.Connection;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;

/**
 * Bài 2 - Truy xuất danh mục thuốc (Pharmacy Catalogue)
 */
public class Bai2 {
    /*
     * PHẦN 1 - PHÂN TÍCH:
     *
     * - if (rs.next()) chỉ phù hợp khi bạn chỉ cần xử lý 1 dòng (ví dụ: đọc bản ghi đầu tiên).
     *   Yêu cầu bài này là "in danh sách" => phải duyệt TOÀN BỘ các dòng => cần vòng lặp (while/do-while).
     *
     * - ResultSet hoạt động như một con trỏ (cursor) trỏ vào các dòng kết quả:
     *   + Ban đầu con trỏ đứng TRƯỚC dòng đầu tiên.
     *   + Mỗi lần gọi rs.next(): con trỏ DI CHUYỂN sang dòng kế tiếp.
     *       * Nếu có dòng: trả về true và bạn có thể đọc cột ở dòng đó.
     *       * Nếu hết dòng hoặc bảng trống: trả về false.
     *   => Nếu chỉ dùng if (rs.next()) thì bạn chỉ đọc được đúng 1 dòng (dòng đầu tiên) rồi kết thúc.
     *   => Nếu bảng trống, rs.next() trả false và khối if không chạy (thường gây "không in gì" hoặc code khác dễ lỗi).
     *
     * PHẦN 2 - THỰC THI:
     * - Sửa lại mã nguồn, sử dụng vòng lặp while(rs.next()) để in toàn bộ danh mục thuốc.
     */
    public static void printPharmacyCatalogue() {
        Connection conn = null;
        Statement stmt = null;
        ResultSet rs = null;

        final String sql = "SELECT medicine_name, stock FROM Pharmacy";

        try {
            conn = DBContext.getConnection();
            stmt = conn.createStatement();
            rs = stmt.executeQuery(sql);

            System.out.println("=== PHARMACY CATALOGUE ===");
            System.out.printf("%-30s | %s%n", "Medicine Name", "Stock");
            System.out.println("-----------------------------------------------");

            boolean hasAnyRow = false;
            while (rs.next()) {
                hasAnyRow = true;
                String name = rs.getString("medicine_name");
                int stock = rs.getInt("stock");
                System.out.printf("%-30s | %d%n", name, stock);
            }

            if (!hasAnyRow) {
                System.out.println("(Catalogue is empty)");
            }

        } catch (SQLException e) {
            System.err.println("DB error while loading pharmacy catalogue: " + e.getMessage());
        } finally {
            DBContext.closeQuietly(rs);
            DBContext.closeQuietly(stmt);
            DBContext.closeQuietly(conn);
        }
    }

    public static void main(String[] args) {
        printPharmacyCatalogue();
    }
}

package org.example.bai3;

import org.example.bai1.DBContext;

import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.SQLException;

/**
 * Bài 3 - Cập nhật tình trạng giường bệnh (Bed Management)
 */
public class Bai3 {
    /*
     * PHẦN 1 - PHÂN TÍCH:
     *
     * - executeUpdate() trả về số DÒNG (rows) bị tác động bởi câu lệnh DML
     *   (INSERT / UPDATE / DELETE).
     *   Ví dụ:
     *   + Trả về 1: có 1 dòng được update thành công.
     *   + Trả về 0: không có dòng nào bị thay đổi (thường do WHERE không match bản ghi nào).
     *
     * - Ứng dụng vào bài:
     *   Khi cập nhật theo bed_id, nếu executeUpdate() == 0 => bed_id không tồn tại
     *   (hoặc dữ liệu đã ở trạng thái đó và DB không tính là thay đổi tùy hệ quản trị).
     *   Ta dùng giá trị này để phản hồi chính xác cho y tá: "Mã giường này không tồn tại".
     */

    /*
     * PHẦN 2 - THỰC THI:
     * Cập nhật trạng thái giường theo bedId.
     * Lưu ý: tên bảng/cột có thể cần chỉnh theo DB thực tế.
     */
    public static void updateBedStatusToOccupied(String bedId) {
        Connection conn = null;
        PreparedStatement ps = null;

        final String sql = "UPDATE Beds SET bed_status = ? WHERE bed_id = ?";

        try {
            conn = DBContext.getConnection();
            ps = conn.prepareStatement(sql);
            ps.setString(1, "Occupied");
            ps.setString(2, bedId);

            int affectedRows = ps.executeUpdate();

            if (affectedRows == 0) {
                System.err.println("Lỗi: Không tìm thấy mã giường: " + bedId);
            } else {
                System.out.println("Đã cập nhật giường '" + bedId + "' sang trạng thái Đang sử dụng.");
            }

        } catch (SQLException e) {
            System.err.println("DB error while updating bed status: " + e.getMessage());
        } finally {
            DBContext.closeQuietly(ps);
            DBContext.closeQuietly(conn);
        }
    }

    public static void main(String[] args) {
        String bedId = (args != null && args.length > 0) ? args[0] : "Bed_999";
        updateBedStatusToOccupied(bedId);
    }
}

package org.example.bai4;

import org.example.bai1.DBContext;

import java.sql.Connection;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;

/*
 * Bài 4 - Tra cứu bệnh nhân & Hiểm họa rò rỉ thông tin (SQL Injection)
 *
 * Lưu ý: Bài yêu cầu dùng Statement + lọc ký tự đặc biệt trước khi query.
 * (Trong thực tế nên dùng PreparedStatement để chống SQL Injection tốt hơn.)
 */
public class Bai4 {

    /*
     * PHẦN 1 - PHÂN TÍCH:
     *
     * Code lỗi thường kiểu:
     *   String patientName = input;
     *   String sql = "SELECT * FROM Patients WHERE full_name = '" + patientName + "'";
     *
     * Nếu attacker nhập:  ' OR '1'='1'; --
     * => sql sau khi nối chuỗi trở thành:
     *   SELECT * FROM Patients WHERE full_name = '' OR '1'='1'; --'
     *
     * Giải thích vì sao WHERE luôn đúng (true):
     * - Điều kiện WHERE gồm 2 vế nối bởi OR:
     *     full_name = ''   OR   '1'='1'
     * - '1'='1' luôn là TRUE, nên cả biểu thức luôn TRUE bất kể full_name là gì.
     * - Phần "--" biến phần còn lại của câu lệnh thành comment (tùy DB), giúp tránh lỗi dấu nháy.
     * Kết quả: query trả về TẤT CẢ bệnh nhân thay vì 1 người.
     */

    /*
     * PHẦN 2 - THỰC THI (theo yêu cầu đề):
     * - Trước khi build SQL bằng Statement, kiểm tra & loại bỏ các ký tự/chuỗi đặc biệt như: --, ;, '
     * - Sau đó mới nối chuỗi và thực thi.
     */

    /*
     * Sanitizer đơn giản theo yêu cầu đề.
     * Cảnh báo: cách này KHÔNG an toàn tuyệt đối (có nhiều biến thể injection).
     * Best practice ngoài đời: PreparedStatement + phân quyền DB + logging/auditing.
     */
    public static String sanitizePatientName(String input) {
        if (input == null) return "";

        String s = input;

        // loại bỏ comment injection
        s = s.replace("--", "");

        // loại bỏ statement terminator
        s = s.replace(";", "");

        // loại bỏ dấu nháy đơn để tránh đóng chuỗi
        s = s.replace("'", "");

        // có thể trim để giảm rác
        return s.trim();
    }

    public static void findPatientsByNameUsingStatement(String rawNameInput) {
        Connection conn = null;
        Statement stmt = null;
        ResultSet rs = null;

        String safeName = sanitizePatientName(rawNameInput);

        // vẫn dùng Statement (theo đề), nhưng đã lọc ký tự đặc biệt trước khi nối chuỗi
        String sql = "SELECT patient_id, full_name FROM Patients WHERE full_name = '" + safeName + "'";

        try {
            conn = DBContext.getConnection();
            stmt = conn.createStatement();
            rs = stmt.executeQuery(sql);

            boolean hasAny = false;
            while (rs.next()) {
                hasAny = true;
                String id = rs.getString("patient_id");
                String name = rs.getString("full_name");
                System.out.println(id + " | " + name);
            }

            if (!hasAny) {
                System.out.println("Không tìm thấy bệnh nhân với tên: " + safeName);
            }

        } catch (SQLException e) {
            System.err.println("DB error while searching patient: " + e.getMessage());
        } finally {
            DBContext.closeQuietly(rs);
            DBContext.closeQuietly(stmt);
            DBContext.closeQuietly(conn);
        }
    }

    public static void main(String[] args) {
        String input = (args != null && args.length > 0) ? args[0] : "' OR '1'='1'; --";
        System.out.println("Raw input: " + input);
        System.out.println("Sanitized: " + sanitizePatientName(input));
        findPatientsByNameUsingStatement(input);
    }
}

