package org.example.bai5.dao;

import org.example.bai1.DBContext;
import org.example.bai5.model.Doctor;

import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.ArrayList;
import java.util.List;

/**
 * DAO layer: thao tác DB với bảng Doctors.
 */
public class DoctorDao {

    // NOTE: Tên bảng/cột có thể cần chỉnh theo DB thực tế.
    private static final String SQL_SELECT_ALL =
            "SELECT doctor_id, full_name, specialty FROM Doctors ORDER BY doctor_id";

    private static final String SQL_INSERT =
            "INSERT INTO Doctors (doctor_id, full_name, specialty) VALUES (?, ?, ?)";

    private static final String SQL_GROUP_BY_SPECIALTY =
            "SELECT specialty, COUNT(*) AS total FROM Doctors GROUP BY specialty ORDER BY total DESC";

    public List<Doctor> findAll() throws SQLException {
        Connection conn = null;
        PreparedStatement ps = null;
        ResultSet rs = null;
        List<Doctor> doctors = new ArrayList<>();

        try {
            conn = DBContext.getConnection();
            ps = conn.prepareStatement(SQL_SELECT_ALL);
            rs = ps.executeQuery();

            while (rs.next()) {
                Doctor d = new Doctor();
                d.setId(rs.getString("doctor_id"));
                d.setFullName(rs.getString("full_name"));
                d.setSpecialty(rs.getString("specialty"));
                doctors.add(d);
            }
            return doctors;
        } finally {
            DBContext.closeQuietly(rs);
            DBContext.closeQuietly(ps);
            DBContext.closeQuietly(conn);
        }
    }

    public int insert(Doctor doctor) throws SQLException {
        Connection conn = null;
        PreparedStatement ps = null;

        try {
            conn = DBContext.getConnection();
            ps = conn.prepareStatement(SQL_INSERT);
            ps.setString(1, doctor.getId());
            ps.setString(2, doctor.getFullName());
            ps.setString(3, doctor.getSpecialty());

            return ps.executeUpdate();
        } finally {
            DBContext.closeQuietly(ps);
            DBContext.closeQuietly(conn);
        }
    }

    public List<SpecialtyStat> countBySpecialty() throws SQLException {
        Connection conn = null;
        PreparedStatement ps = null;
        ResultSet rs = null;
        List<SpecialtyStat> stats = new ArrayList<>();

        try {
            conn = DBContext.getConnection();
            ps = conn.prepareStatement(SQL_GROUP_BY_SPECIALTY);
            rs = ps.executeQuery();

            while (rs.next()) {
                String specialty = rs.getString("specialty");
                int total = rs.getInt("total");
                stats.add(new SpecialtyStat(specialty, total));
            }

            return stats;
        } finally {
            DBContext.closeQuietly(rs);
            DBContext.closeQuietly(ps);
            DBContext.closeQuietly(conn);
        }
    }

    public static final class SpecialtyStat {
        private final String specialty;
        private final int total;

        public SpecialtyStat(String specialty, int total) {
            this.specialty = specialty;
            this.total = total;
        }

        public String getSpecialty() {
            return specialty;
        }

        public int getTotal() {
            return total;
        }
    }
}

package org.example.bai5.model;

/**
 * Model: Doctor (bác sĩ trực ca)
 */
public class Doctor {
    private String id;
    private String fullName;
    private String specialty;

    public Doctor() {
    }

    public Doctor(String id, String fullName, String specialty) {
        this.id = id;
        this.fullName = fullName;
        this.specialty = specialty;
    }

    public String getId() {
        return id;
    }

    public void setId(String id) {
        this.id = id;
    }

    public String getFullName() {
        return fullName;
    }

    public void setFullName(String fullName) {
        this.fullName = fullName;
    }

    public String getSpecialty() {
        return specialty;
    }

    public void setSpecialty(String specialty) {
        this.specialty = specialty;
    }

    @Override
    public String toString() {
        return "Doctor{" +
                "id='" + id + '\'' +
                ", fullName='" + fullName + '\'' +
                ", specialty='" + specialty + '\'' +
                '}';
    }
}

package org.example.bai5.presentation;

import org.example.bai5.dao.DoctorDao;
import org.example.bai5.model.Doctor;
import org.example.bai5.service.DoctorService;

import java.sql.SQLException;
import java.util.List;
import java.util.Scanner;

/**
 * Presentation layer: menu console chạy liên tục.
 */
public class ConsoleMenu {

    private final DoctorService doctorService;

    public ConsoleMenu(DoctorService doctorService) {
        this.doctorService = doctorService;
    }

    public void start() {
        try (Scanner sc = new Scanner(System.in)) {
            while (true) {
                printMenu();
                System.out.print("Chọn chức năng (1-4): ");
                String choice = sc.nextLine().trim();

                switch (choice) {
                    case "1" -> handleListDoctors();
                    case "2" -> handleAddDoctor(sc);
                    case "3" -> handleSpecialtyStats();
                    case "4" -> {
                        System.out.println("Thoát chương trình.");
                        return;
                    }
                    default -> System.out.println("Lựa chọn không hợp lệ. Vui lòng chọn 1-4.");
                }

                System.out.println();
            }
        }
    }

    private void printMenu() {
        System.out.println("===== Rikkei-Care | Doctor On-call Management =====");
        System.out.println("1. Xem danh sách bác sĩ");
        System.out.println("2. Thêm bác sĩ mới");
        System.out.println("3. Thống kê chuyên khoa");
        System.out.println("4. Thoát");
    }

    private void handleListDoctors() {
        try {
            List<Doctor> doctors = doctorService.getAllDoctors();
            if (doctors.isEmpty()) {
                System.out.println("Danh sách bác sĩ đang trống.");
                return;
            }

            System.out.printf("%-15s | %-30s | %-20s%n", "Mã số", "Họ tên", "Chuyên khoa");
            System.out.println("---------------------------------------------------------------------");
            for (Doctor d : doctors) {
                System.out.printf("%-15s | %-30s | %-20s%n",
                        d.getId(),
                        d.getFullName(),
                        d.getSpecialty());
            }
            System.out.println("Tổng: " + doctors.size());
        } catch (SQLException e) {
            System.err.println("Lỗi DB khi lấy danh sách bác sĩ: " + e.getMessage());
        }
    }

    private void handleAddDoctor(Scanner sc) {
        System.out.print("Nhập mã bác sĩ: ");
        String id = sc.nextLine();
        System.out.print("Nhập họ tên: ");
        String fullName = sc.nextLine();
        System.out.print("Nhập chuyên khoa: ");
        String specialty = sc.nextLine();

        try {
            int affected = doctorService.addDoctor(id, fullName, specialty);
            if (affected == 1) {
                System.out.println("Thêm bác sĩ thành công.");
            } else {
                // Hiếm gặp: insert không tác động dòng nào
                System.out.println("Thêm bác sĩ thất bại (không có dòng nào được thêm).");
            }
        } catch (DoctorService.ValidationException e) {
            System.out.println("Dữ liệu không hợp lệ: " + e.getMessage());
        } catch (SQLException e) {
            // Kịch bản lỗi thường gặp: trùng PK, vượt độ dài cột, lỗi kiểu dữ liệu...
            System.err.println("Lỗi DB khi thêm bác sĩ: " + e.getMessage());
        }
    }

    private void handleSpecialtyStats() {
        try {
            List<DoctorDao.SpecialtyStat> stats = doctorService.getSpecialtyStats();
            if (stats.isEmpty()) {
                System.out.println("Chưa có dữ liệu để thống kê.");
                return;
            }

            System.out.printf("%-25s | %s%n", "Chuyên khoa", "Số lượng");
            System.out.println("--------------------------------------");
            for (DoctorDao.SpecialtyStat s : stats) {
                System.out.printf("%-25s | %d%n", s.getSpecialty(), s.getTotal());
            }
        } catch (SQLException e) {
            System.err.println("Lỗi DB khi thống kê chuyên khoa: " + e.getMessage());
        }
    }

    /**
     * Liệt kê kịch bản lỗi (để nộp bài):
     *
     * 1) Nhập trùng mã bác sĩ (Primary Key) -> INSERT báo lỗi duplicate key.
     * 2) Nhập chuyên khoa/họ tên quá dài so với độ rộng cột DB -> Data too long.
     * 3) Nhập rỗng (id/name/specialty) -> nghiệp vụ từ chối (ValidationException).
     * 4) Sai định dạng ngày tháng (nếu DB có cột date và nhập từ console) -> parse error / SQL type mismatch.
     * 5) Mất kết nối DB / timeout -> SQLException communications link failure.
     * 6) Không đủ quyền truy cập bảng Doctors -> SQLException permission denied.
     */
}

package org.example.bai5.service;

import org.example.bai5.dao.DoctorDao;
import org.example.bai5.model.Doctor;

import java.sql.SQLException;
import java.util.List;

/**
 * Business layer: validate input + xử lý nghiệp vụ.
 */
public class DoctorService {

    // Có thể chỉnh theo độ rộng cột thật trong DB
    public static final int MAX_ID_LENGTH = 20;
    public static final int MAX_NAME_LENGTH = 100;
    public static final int MAX_SPECIALTY_LENGTH = 50;

    private final DoctorDao doctorDao;

    public DoctorService(DoctorDao doctorDao) {
        this.doctorDao = doctorDao;
    }

    public List<Doctor> getAllDoctors() throws SQLException {
        return doctorDao.findAll();
    }

    public int addDoctor(String id, String fullName, String specialty) throws ValidationException, SQLException {
        id = safeTrim(id);
        fullName = safeTrim(fullName);
        specialty = safeTrim(specialty);

        if (id.isEmpty()) throw new ValidationException("Mã bác sĩ không được để trống.");
        if (fullName.isEmpty()) throw new ValidationException("Họ tên không được để trống.");
        if (specialty.isEmpty()) throw new ValidationException("Chuyên khoa không được để trống.");

        if (id.length() > MAX_ID_LENGTH) {
            throw new ValidationException("Mã bác sĩ quá dài (tối đa " + MAX_ID_LENGTH + " ký tự).");
        }
        if (fullName.length() > MAX_NAME_LENGTH) {
            throw new ValidationException("Họ tên quá dài (tối đa " + MAX_NAME_LENGTH + " ký tự).");
        }
        if (specialty.length() > MAX_SPECIALTY_LENGTH) {
            throw new ValidationException("Chuyên khoa quá dài (tối đa " + MAX_SPECIALTY_LENGTH + " ký tự).");
        }

        Doctor d = new Doctor(id, fullName, specialty);
        return doctorDao.insert(d);
    }

    public List<DoctorDao.SpecialtyStat> getSpecialtyStats() throws SQLException {
        return doctorDao.countBySpecialty();
    }

    private static String safeTrim(String s) {
        return s == null ? "" : s.trim();
    }

    public static class ValidationException extends Exception {
        public ValidationException(String message) {
            super(message);
        }
    }
}
